    # Server-side validation
    if not re.match(r'^\d{3}-\d{2}-\d{4}$', ssn):
        return jsonify({"error": "Invalid SSN format"}), 400

    # Encrypt the SSN
    encrypted_ssn = cipher_suite.encrypt(ssn.encode())

    # Store the encrypted SSN securely (e.g., in a database)
    # For demonstration purposes, we'll just print it
    print(f"Encrypted SSN: {encrypted_ssn}")

    return jsonify({"message": "SSN received successfully", "encrypted_ssn": encrypted_ssn.decode()})

if __name__ == '__main__':
    app.run(debug=True, ssl_context='adhoc')  # Run with SSL context for HTTPS
```

